export const useHandleUploadDocument = () => {
  const queryClient = useQueryClient();
  const {
    visible: documentUploadVisible,
    hideModal: hideDocumentUploadModal,
    showModal: showDocumentUploadModal,
  } = useSetModalState();
  const [fileList, setFileList] = useState<UploadFile[]>([]);
  const [uploadProgress, setUploadProgress] = useState<number>(0);
  const { uploadDocument, loading } = useUploadNextDocument();
  const { runDocumentByIds } = useRunNextDocument();

  const MAX_BATCH_FILES = 25;
  const MAX_BATCH_BYTES = 512 * 1024 * 1024; // stay well below default 1GB server limit

  const getFileSize = (file: UploadFile) => {
    const raw = (file as any).originFileObj ?? file;
    return (raw && raw.size) || 0;
  };

  const splitIntoBatches = useCallback(
    (files: UploadFile[]) => {
      const batches: UploadFile[][] = [];
      let current: UploadFile[] = [];
      let currentSize = 0;

      files.forEach((file) => {
        const size = getFileSize(file);
        const exceedsCount = current.length >= MAX_BATCH_FILES;
        const exceedsSize =
          currentSize + size > MAX_BATCH_BYTES && current.length > 0;

        if (exceedsCount || exceedsSize) {
          batches.push(current);
          current = [];
          currentSize = 0;
        }

        current.push(file);
        currentSize += size;
      });

      if (current.length) {
        batches.push(current);
      }

      return batches;
    },
    [MAX_BATCH_BYTES, MAX_BATCH_FILES],
  );

  const onDocumentUploadOk = useCallback(
    async ({
      parseOnCreation,
      reviewBeforeChunk = false,
      directoryFileList,
    }: {
      directoryFileList: UploadFile[];
      parseOnCreation: boolean;
      reviewBeforeChunk?: boolean;
    }): Promise<number | undefined> => {
      const processFileGroup = async (filesPart: UploadFile[]) => {
        // set status to uploading on files
        setFileList((prev) =>
          prev.map((file) => {
            if (!filesPart.includes(file)) {
              return file;
            }
            return { ...file, status: 'uploading', percent: 1 };
          }),
        );

        const ret = await uploadDocument(filesPart, {
          reviewBeforeChunk,
        });

        const files = ret?.data || [];
        const successfulFilenames = files.map((file: any) => file.name);

        // set status to done or error on files (based on response)
        setFileList((prev) =>
          prev.map((file) => {
            if (!filesPart.includes(file)) {
              return file;
            }

            const isSuccess = successfulFilenames.includes(file.name);
            return {
              ...file,
              status: isSuccess ? 'done' : 'error',
              percent: 100,
              response: ret?.message,
            };
          }),
        );

        return {
          code: ret?.code,
          reviewDocIds: files
            .filter(
              (doc: any) => doc?.parser_config?.ocr_review?.review_required,
            )
            .map((file: any) => file.id),
          autoRunDocIds: files
            .filter(
              (doc: any) => !doc?.parser_config?.ocr_review?.review_required,
            )
            .map((file: any) => file.id),
          totalSuccess: successfulFilenames.length,
        };
      };
      const allFiles = [...directoryFileList, ...fileList];
      const totalFiles = allFiles.length;

      if (totalFiles === 0) {
        hideDocumentUploadModal();
        return 0;
      }

      const batches = splitIntoBatches(allFiles);
      let totalSuccess = 0;
      let codes: Array<number | undefined> = [];
      let toRunFileIds: string[] = [];
      let toReviewFileIds: string[] = [];

      let uploaded = 0;
      for (const files of batches) {
        const {
          code,
          totalSuccess: count,
          reviewDocIds,
          autoRunDocIds,
        } = await processFileGroup(files);
        codes.push(code);
        totalSuccess += count;
        toRunFileIds = toRunFileIds.concat(autoRunDocIds);
        toReviewFileIds = toReviewFileIds.concat(reviewDocIds);
        uploaded += files.length;
        setUploadProgress(Math.floor((uploaded / totalFiles) * 100));
      }

      const allSuccess = codes.every((code) => code === 0);
      const any500 = codes.some((code) => code === 500);

      let code = 500;
      if (allSuccess || (any500 && totalSuccess === totalFiles)) {
        code = 0;
        hideDocumentUploadModal();
      }

      const uniqueReviewFileIds = Array.from(new Set(toReviewFileIds));
      const uniqueRunFileIds = Array.from(new Set(toRunFileIds));
      if (
        uniqueRunFileIds.length > 0 &&
        (parseOnCreation || reviewBeforeChunk)
      ) {
        await runDocumentByIds({
          documentIds: uniqueRunFileIds,
          run: 1,
          shouldDelete: false,
        });
      }
      await queryClient.invalidateQueries({ queryKey: ['fetchDocumentList'] });

      if (uniqueReviewFileIds.length > 0) {
        // Run OCR review initialization in background to avoid blocking modal interaction.
        void kbService
          .ocr_review_init({
            doc_ids: uniqueReviewFileIds,
          })
          .finally(() => {
            queryClient.invalidateQueries({ queryKey: ['fetchDocumentList'] });
          });
      }

      setUploadProgress(100);

      return code;
    },
    [
      fileList,
      uploadDocument,
      hideDocumentUploadModal,
      runDocumentByIds,
      splitIntoBatches,
      queryClient,
    ],
  );

  return {
    documentUploadLoading: loading,
    onDocumentUploadOk,
    documentUploadVisible,
    hideDocumentUploadModal,
    showDocumentUploadModal,
    uploadFileList: fileList,
    setUploadFileList: setFileList,
    uploadProgress,
    setUploadProgress,
  };
};

export const useHandleWebCrawl = () => {
  const {
    visible: webCrawlUploadVisible,
    hideModal: hideWebCrawlUploadModal,
    showModal: showWebCrawlUploadModal,
  } = useSetModalState();
  const { webCrawl, loading } = useNextWebCrawl();

  const onWebCrawlUploadOk = useCallback(
    async (name: string, url: string) => {
      const ret = await webCrawl({ name, url });
      if (ret === 0) {
        hideWebCrawlUploadModal();
        return 0;
      }
      return -1;
    },
    [webCrawl, hideWebCrawlUploadModal],
  );

  return {
    webCrawlUploadLoading: loading,
    onWebCrawlUploadOk,
    webCrawlUploadVisible,
    hideWebCrawlUploadModal,
    showWebCrawlUploadModal,
  };
};

export const useHandleRunDocumentByIds = (id: string) => {
  const { runDocumentByIds, loading } = useRunNextDocument();
  const [currentId, setCurrentId] = useState<string>('');
  const isLoading = loading && currentId !== '' && currentId === id;

  const handleRunDocumentByIds = async (
    documentId: string,
    isRunning: boolean,
    shouldDelete: boolean = false,
  ) => {
    if (isLoading) {
      return;
    }
    setCurrentId(documentId);
    try {
      await runDocumentByIds({
        documentIds: [documentId],
        run: isRunning ? 2 : 1,
        shouldDelete,
      });
      setCurrentId('');
    } catch (error) {
      setCurrentId('');
    }
  };

  return {
    handleRunDocumentByIds,
    loading: isLoading,
  };
};

